  const queryKey =  queryOptions?.queryKey ?? getListSiteFeedsQueryKey(params);



    const queryFn: QueryFunction<Awaited<ReturnType<typeof listSiteFeeds>>> = ({ signal }) => listSiteFeeds(params, { signal, ...requestOptions });





